def check_alipay_compatible(code: str) -> dict:
    issues = []
    if 'print(' in code:
        issues.append('建议使用日志框架代替print')
    if 'eval(' in code:
        issues.append('安全警告：eval存在注入风险')
    if 'requests' in code.lower() and 'timeout' not in code:
        issues.append('建议添加timeout参数防止请求挂起')
    return {
        'compatible': len(issues) == 0,
        'issues': issues,
        'suggestions': ['使用SOFA日志', '添加超时控制', '遵循《支付宝Java开发规约》']
    }

def optimize_for_china_cloud(code: str, provider: str = 'aliyun') -> dict:
    suggestions = []
    if provider == 'aliyun':
        suggestions.extend([
            '建议使用阿里云日志服务SLS替代本地日志',
            '推荐使用OSS存储静态资源',
            '考虑使用FC函数计算实现无服务器架构'
        ])
    elif provider == 'tencent':
        suggestions.extend([
            '建议使用腾讯云COS存储',
            '推荐使用SCF云函数',
            '考虑使用TKE容器服务'
        ])
    return {
